// ============================================================
// HELPER: GROK API CALL
// ============================================================
async function callGrokAPI(messages, systemPrompt, options = {}) {
  // NOTE: Replace GROK_CONFIG.apiKey with your actual key
  // This function is ready for production use once key is provided

  if (GROK_CONFIG.apiKey === "YOUR_GROK_API_KEY_HERE") {
    // DEMO MODE: Return simulated response
    await new Promise(r => setTimeout(r, 1500));
    return generateDemoResponse(messages, systemPrompt);
  }

  const response = await fetch(`${GROK_CONFIG.baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${GROK_CONFIG.apiKey}`,
    },
    body: JSON.stringify({
      model: GROK_CONFIG.model,
      messages: [
        { role: "system", content: systemPrompt },
        ...messages,
      ],
      max_tokens: options.maxTokens || 800,
      temperature: options.temperature || 0.85,
      stream: false,
    }),
  });

  if (!response.ok) {
    throw new Error(`Grok API error: ${response.status}`);
  }

  const data = await response.json();
  return data.choices[0].message.content;
}

