// ============================================================
// AUTH SCREEN
// ============================================================
function AuthScreen({ onComplete }) {
  const [mode, setMode] = useState("login");
  const [age, setAge] = useState("");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [ageError, setAgeError] = useState("");

  const getContentRating = (ageVal) => {
    const a = parseInt(ageVal);
    if (a < 13) return "E";
    if (a < 18) return "T";
    return "M";
  };

  const handleSubmit = () => {
    const a = parseInt(age);
    if (!age || isNaN(a) || a < 4 || a > 120) {
      setAgeError("Please enter a valid age (4-120)");
      return;
    }
    if (!name.trim()) return;
    const rating = getContentRating(a);
    onComplete({ name, email, age: a, contentRating: rating });
  };

  return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div className="card" style={{ maxWidth: 440, width: "100%", animation: "fadeIn 0.5s ease" }}>
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <img src={SILVERFANG_LOGO} alt="SilverFang Library" style={{ width: 80, height: 80, objectFit: "contain", marginBottom: 4, filter: "drop-shadow(0 0 12px rgba(59,130,246,0.5))" }} />
          <p style={{ fontFamily: "'Cinzel', serif", fontSize: 10, color: "#4a7fa8", letterSpacing: 4, textTransform: "uppercase", marginBottom: 2 }}>DIREWOLF AI</p>
          <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8f4ff", fontSize: 20, letterSpacing: 2 }}>SILVERFANG LIBRARY</h2>
          <p style={{ color: "#6b7280", fontSize: 14, marginTop: 8 }}>
            {mode === "login" ? "Welcome back, storyteller" : "Your saga begins here"}
          </p>
        </div>

        <div style={{ display: "flex", gap: 4, background: "#060d18", borderRadius: 6, padding: 4, marginBottom: 28 }}>
          {["login", "register"].map(m => (
            <button key={m} onClick={() => setMode(m)} style={{
              flex: 1, padding: "10px", background: mode === m ? "#1a2a3a" : "transparent",
              border: mode === m ? "1px solid #c9913a44" : "1px solid transparent",
              borderRadius: 4, color: mode === m ? "#e8c060" : "#6b7280",
              fontFamily: "'Cinzel', serif", fontSize: 12, letterSpacing: 1,
              cursor: "pointer", textTransform: "uppercase", transition: "all 0.2s",
            }}>
              {m === "login" ? "Sign In" : "Create Account"}
            </button>
          ))}
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div>
            <label style={{ fontSize: 12, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>
              Storyteller Name
            </label>
            <input value={name} onChange={e => setName(e.target.value)} placeholder="What shall we call you?" style={{ marginTop: 6 }} />
          </div>
          <div>
            <label style={{ fontSize: 12, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>
              Email
            </label>
            <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com" style={{ marginTop: 6 }} />
          </div>
          <div>
            <label style={{ fontSize: 12, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>
              Your Age <span style={{ color: "#c9913a", fontSize: 10 }}>(sets content rating)</span>
            </label>
            <input type="number" value={age} onChange={e => { setAge(e.target.value); setAgeError(""); }} placeholder="Age" style={{ marginTop: 6 }} />
            {ageError && <p style={{ color: "#ef4444", fontSize: 12, marginTop: 4 }}>{ageError}</p>}
            {age && !ageError && parseInt(age) >= 4 && (
              <div style={{ marginTop: 8, padding: "8px 12px", background: "#0a1a0a", border: "1px solid #22c55e33", borderRadius: 4 }}>
                <span style={{ fontSize: 13, color: "#22c55e" }}>
                  Content Rating: {CONTENT_RATINGS[getContentRating(age)]?.label}
                </span>
                <p style={{ fontSize: 12, color: "#6b7280", marginTop: 2 }}>
                  {CONTENT_RATINGS[getContentRating(age)]?.description}
                </p>
              </div>
            )}
          </div>
        </div>

        <button className="btn-primary" onClick={handleSubmit} style={{ width: "100%", marginTop: 28, justifyContent: "center" }}>
          {mode === "login" ? "Enter the Forge" : "Create My Account"}
        </button>

        <p style={{ textAlign: "center", fontSize: 11, color: "#3a4a5a", marginTop: 16, lineHeight: 1.5 }}>
          Age verification is used solely for content rating. We comply with COPPA and GDPR.
        </p>
      </div>
    </div>
  );
}

