// ============================================================
// STORY SETUP SCREEN
// ============================================================
function StorySetupScreen({ user, subscription, stories, onCreate, onBack }) {
  const [step, setStep] = useState(1);
  const [genre, setGenre] = useState(null);
  const [customInstructions, setCustomInstructions] = useState("");
  const [rating, setRating] = useState(user?.contentRating || "T");
  const [title, setTitle] = useState("");
  const [params, setParams] = useState({});
  const [multiplayer, setMultiplayer] = useState(false);
  const [errors, setErrors] = useState([]);

  const tier = SUBSCRIPTION_TIERS[subscription];
  const selectedGenre = STORY_GENRES[genre];
  const canShare = subscription !== "free";

  const availableRatings = Object.entries(CONTENT_RATINGS).filter(([k, v]) => v.minAge <= user?.age);

  const handleParamChange = (key, value) => {
    setParams(prev => ({ ...prev, [key]: value }));
    const newErrors = [];
    if (genre === "horror" && rating !== "M" && rating !== "A") {
      newErrors.push("Horror genre requires Mature (M) or Adult (A) rating.");
    }
    setErrors(newErrors);
  };

  const canProceed = () => {
    if (step === 1) return !!genre;
    if (step === 2) return true; // custom instructions are optional
    if (step === 3) return rating && !errors.length;
    if (step === 4) return title.trim().length > 0;
    return true;
  };

  const handleCreate = () => {
    onCreate({ genre, customInstructions, rating, title, params, multiplayer });
  };

  // Inspiration prompts that populate the textarea as a starting point
  const INSTRUCTION_PROMPTS = {
    fantasy:   ["My protagonist is a disgraced knight seeking redemption", "The magic system is based on music and sound", "I want a slow-burn reluctant alliance between rivals", "The villain believes they are the true hero"],
    romance:   ["The leads knew each other as children but haven't met since", "One character is hiding a life-changing secret from the other", "Set against the backdrop of a family business rivalry", "I want lots of witty banter and tension before any romance"],
    scifi:     ["The ship AI has developed genuine emotions", "Faster-than-light travel has a psychological cost on the traveler", "Earth is uninhabitable — humanity lives on orbital stations", "I want political intrigue between human factions, not aliens"],
    mystery:   ["The detective has a personal connection to the victim", "Every suspect has a compelling reason to lie", "The solution should involve a clue hidden in plain sight early on", "I want an unreliable narrator — the reader can't fully trust the protagonist"],
    murder_mystery: ["The victim was universally disliked but for different reasons", "The killer is the most sympathetic character", "I want the detective to nearly accuse the wrong person first", "The murder method should be elegant and unexpected"],
    horror:    ["The horror is ambiguous — never confirm if it's real or imagined", "A child is the first to understand what's happening", "I want creeping dread, not jump scares", "The monster is a metaphor for grief"],
    western:   ["My protagonist is trying to leave their violent past behind", "The town is hiding something dark under its respectable surface", "I want a female gunslinger as the lead", "The antagonist has a code of honor even if it's brutal"],
    thriller:  ["The protagonist can't trust anyone, including their own memories", "The conspiracy goes higher than anyone expects", "A ticking clock — something happens in 48 hours", "The antagonist and protagonist respect each other"],
    historical:["Include real historical figures as minor characters", "The protagonist is on the losing side of history", "I want period-accurate dialogue and culture, no modern sensibilities", "Focus on the lives of ordinary people during an extraordinary event"],
  };

  const suggestions = INSTRUCTION_PROMPTS[genre] || [];

  const steps = [
    { n: 1, label: "Genre" },
    { n: 2, label: "Your Story" },
    { n: 3, label: "Rating" },
    { n: 4, label: "Setup" },
    { n: 5, label: "Launch" },
  ];

  return (
    <div style={{ minHeight: "100vh", padding: "24px 20px", maxWidth: 760, margin: "0 auto" }}>
      {/* Progress */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 40 }}>
        <button className="btn-ghost" onClick={onBack} style={{ padding: "8px 16px", fontSize: 12 }}>← Back</button>
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 4 }}>
          {steps.map((s, i) => (
            <div key={s.n} style={{ display: "flex", alignItems: "center", gap: 4 }}>
              <div style={{
                width: 32, height: 32, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center",
                background: step === s.n ? "#c9913a" : step > s.n ? "#22c55e" : "#1e2d3d",
                color: step >= s.n ? "#1a0f00" : "#6b7280",
                fontFamily: "'Cinzel', serif", fontSize: 13, fontWeight: 700,
                cursor: step > s.n ? "pointer" : "default", transition: "all 0.2s",
              }} onClick={() => step > s.n && setStep(s.n)}>
                {step > s.n ? "✓" : s.n}
              </div>
              <span style={{ fontSize: 12, color: step === s.n ? "#c9913a" : "#6b7280", fontFamily: "'Cinzel', serif", letterSpacing: 1 }}>{s.label}</span>
              {i < steps.length - 1 && <div style={{ width: 20, height: 1, background: "#1e2d3d", margin: "0 4px" }} />}
            </div>
          ))}
        </div>
      </div>

      <div style={{ animation: "fadeIn 0.4s ease" }}>
        {/* STEP 1: Genre */}
        {step === 1 && (
          <div>
            <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 26, marginBottom: 8, letterSpacing: 2 }}>CHOOSE YOUR GENRE</h2>
            <p style={{ color: "#6b7280", marginBottom: 28, fontSize: 15 }}>Each genre comes with specialized AI storytelling guidance</p>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))", gap: 16 }}>
              {Object.values(STORY_GENRES).map(g => {
                const locked = g.minRating === "M" && !["M", "A"].includes(user?.contentRating);
                return (
                  <div key={g.id} onClick={() => !locked && setGenre(g.id)} className={locked ? "" : "card-hover"} style={{
                    padding: "20px", borderRadius: 8, cursor: locked ? "not-allowed" : "pointer",
                    background: genre === g.id ? "linear-gradient(135deg, #1a1a05, #1f1800)" : "#0f1827",
                    border: `1px solid ${genre === g.id ? "#c9913a" : locked ? "#0f1827" : "#1e2d3d"}`,
                    opacity: locked ? 0.4 : 1, transition: "all 0.2s",
                  }}>
                    <div style={{ fontSize: 32, marginBottom: 8 }}>{g.icon}</div>
                    <h3 style={{ fontFamily: "'Cinzel', serif", color: genre === g.id ? "#e8c060" : "#c9bfa8", fontSize: 14, letterSpacing: 1, marginBottom: 6 }}>
                      {g.label.replace(/^\S+ /, "")}
                    </h3>
                    <p style={{ fontSize: 13, color: "#6b7280", lineHeight: 1.4 }}>{g.description}</p>
                    {locked && <p style={{ fontSize: 11, color: "#ef4444", marginTop: 6 }}>Requires M+ rating</p>}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* STEP 2: Custom Instructions */}
        {step === 2 && (
          <div>
            <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 26, marginBottom: 8, letterSpacing: 2 }}>YOUR STORY, YOUR RULES</h2>
            <p style={{ color: "#6b7280", marginBottom: 6, fontSize: 15 }}>
              Tell Grok anything specific about the story you want to build. Characters, themes, tone, plot seeds, what to avoid — all fair game.
            </p>
            <p style={{ color: "#3a4a5a", marginBottom: 24, fontSize: 13, fontStyle: "italic" }}>
              This is optional. Skip it and Grok will use creative judgment based on your genre and parameters.
            </p>

            {/* Suggestion chips */}
            <div style={{ marginBottom: 16 }}>
              <p style={{ fontFamily: "'Cinzel', serif", fontSize: 11, color: "#c9913a", letterSpacing: 2, marginBottom: 10 }}>
                ✦ INSPIRATION — click to use as a starting point
              </p>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
                {suggestions.map(s => (
                  <button
                    key={s}
                    onClick={() => setCustomInstructions(prev => prev ? `${prev}\n${s}` : s)}
                    style={{
                      background: "#0a1120", border: "1px solid #1e2d3d", borderRadius: 20,
                      color: "#8aacbf", padding: "6px 14px", fontSize: 13, cursor: "pointer",
                      fontFamily: "'Crimson Text', serif", transition: "all 0.15s", textAlign: "left",
                    }}
                    onMouseEnter={e => { e.currentTarget.style.borderColor = "#c9913a55"; e.currentTarget.style.color = "#e8dcc8"; }}
                    onMouseLeave={e => { e.currentTarget.style.borderColor = "#1e2d3d"; e.currentTarget.style.color = "#8aacbf"; }}
                  >
                    + {s}
                  </button>
                ))}
              </div>
            </div>

            {/* Main textarea */}
            <div style={{ position: "relative" }}>
              <textarea
                value={customInstructions}
                onChange={e => setCustomInstructions(e.target.value)}
                placeholder={`Example:\n"My protagonist is a former assassin named Mira who is trying to go straight. She has a younger brother she's protecting. The tone should be gritty and morally grey — no clear heroes. I don't want any comic relief characters."`}
                rows={9}
                style={{ resize: "vertical", fontSize: 15, lineHeight: 1.7, padding: "16px" }}
              />
              {customInstructions.length > 0 && (
                <button
                  onClick={() => setCustomInstructions("")}
                  style={{
                    position: "absolute", top: 10, right: 10,
                    background: "#1e2d3d", border: "none", borderRadius: 4,
                    color: "#6b7280", fontSize: 11, padding: "4px 8px", cursor: "pointer",
                    fontFamily: "'Cinzel', serif", letterSpacing: 1,
                  }}
                >
                  CLEAR
                </button>
              )}
            </div>

            {/* Character count + tips */}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginTop: 10, gap: 20 }}>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {[
                  "✦ Name specific characters you want to exist from the start",
                  "✦ Describe themes or tones you want the AI to lean into",
                  "✦ Mention things you want the AI to avoid",
                  "✦ Seed a mystery, conflict, or backstory for Grok to build on",
                ].map(tip => (
                  <p key={tip} style={{ fontSize: 12, color: "#3a4a5a", fontStyle: "italic" }}>{tip}</p>
                ))}
              </div>
              <span style={{ fontSize: 12, color: customInstructions.length > 1200 ? "#ef4444" : "#3a4a5a", whiteSpace: "nowrap" }}>
                {customInstructions.length} / 1200
              </span>
            </div>

            {customInstructions.length > 1200 && (
              <div style={{ marginTop: 12, padding: "10px 14px", background: "#3d1010", border: "1px solid #ef4444", borderRadius: 6, color: "#f87171", fontSize: 13 }}>
                ⚠️ Keep instructions under 1200 characters for best results — Grok works better with focused direction than a wall of text.
              </div>
            )}
          </div>
        )}

        {/* STEP 3: Rating */}
        {step === 3 && (
          <div>
            <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 26, marginBottom: 8, letterSpacing: 2 }}>CONTENT RATING</h2>
            <p style={{ color: "#6b7280", marginBottom: 28, fontSize: 15 }}>
              Your age allows ratings up to <span style={{ color: CONTENT_RATINGS[user?.contentRating]?.color }}>{CONTENT_RATINGS[user?.contentRating]?.label}</span>
            </p>
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              {availableRatings.map(([key, r]) => (
                <div key={key} onClick={() => { setRating(key); handleParamChange("rating", key); }} style={{
                  padding: "20px 24px", borderRadius: 8, cursor: "pointer",
                  background: rating === key ? "linear-gradient(135deg, #0a1a0a, #0f1827)" : "#0f1827",
                  border: `1px solid ${rating === key ? r.color : "#1e2d3d"}`,
                  transition: "all 0.2s",
                }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
                    <div style={{ width: 48, height: 48, borderRadius: 8, background: `${r.color}22`, border: `2px solid ${r.color}66`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Cinzel', serif", fontWeight: 700, color: r.color, fontSize: 18 }}>
                      {key}
                    </div>
                    <div>
                      <p style={{ fontFamily: "'Cinzel', serif", color: "#e8dcc8", fontSize: 16, marginBottom: 4 }}>{r.label}</p>
                      <p style={{ color: "#6b7280", fontSize: 14 }}>{r.description}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            {errors.map(e => (
              <div key={e} style={{ marginTop: 16, padding: "12px 16px", background: "#3d1010", border: "1px solid #ef4444", borderRadius: 6, color: "#f87171", fontSize: 14 }}>
                ⚠️ {e}
              </div>
            ))}
          </div>
        )}

        {/* STEP 4: Setup */}
        {step === 4 && (
          <div>
            <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 26, marginBottom: 28, letterSpacing: 2 }}>STORY PARAMETERS</h2>
            <div style={{ marginBottom: 24 }}>
              <label style={{ fontSize: 12, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>Story Title</label>
              <input value={title} onChange={e => setTitle(e.target.value)} placeholder="Give your saga a name..." style={{ marginTop: 8 }} />
            </div>

            {selectedGenre?.parameters?.map(paramKey => {
              const param = GENRE_PARAMETERS[paramKey];
              if (!param) return null;
              return (
                <div key={paramKey} style={{ marginBottom: 20 }}>
                  <label style={{ fontSize: 12, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>{param.label}</label>
                  <select value={params[paramKey] || ""} onChange={e => handleParamChange(paramKey, e.target.value)} style={{ marginTop: 8 }}>
                    <option value="">— Choose (optional) —</option>
                    {param.options.map(o => <option key={o} value={o}>{o}</option>)}
                  </select>
                </div>
              );
            })}

            <div style={{ padding: "16px 20px", background: "#0a1120", border: "1px solid #1e2d3d", borderRadius: 8 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <p style={{ fontFamily: "'Cinzel', serif", color: "#c9bfa8", fontSize: 15, letterSpacing: 1 }}>SHARED STORY MODE</p>
                  <p style={{ color: "#6b7280", fontSize: 13, marginTop: 4 }}>Invite others to co-author this story {!canShare && "— Requires paid plan"}</p>
                </div>
                <button onClick={() => canShare && setMultiplayer(!multiplayer)} style={{
                  width: 52, height: 28, borderRadius: 14, cursor: canShare ? "pointer" : "not-allowed",
                  background: multiplayer && canShare ? "#c9913a" : "#1e2d3d",
                  border: "none", transition: "all 0.3s", position: "relative",
                  opacity: canShare ? 1 : 0.5,
                }}>
                  <div style={{ width: 20, height: 20, borderRadius: "50%", background: "#e8dcc8", position: "absolute", top: 4, left: multiplayer && canShare ? 28 : 4, transition: "left 0.3s" }} />
                </button>
              </div>
            </div>
          </div>
        )}

        {/* STEP 5: Launch */}
        {step === 5 && (
          <div>
            <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 26, marginBottom: 28, letterSpacing: 2 }}>YOUR SAGA AWAITS</h2>
            <div className="card" style={{ marginBottom: 24 }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                {[
                  { label: "Title", value: title },
                  { label: "Genre", value: selectedGenre?.label },
                  { label: "Content Rating", value: CONTENT_RATINGS[rating]?.label },
                  { label: "Mode", value: multiplayer ? "Shared Story" : "Solo" },
                  ...Object.entries(params).filter(([, v]) => v).map(([k, v]) => ({ label: GENRE_PARAMETERS[k]?.label || k, value: v })),
                ].map(({ label, value }) => value ? (
                  <div key={label}>
                    <p style={{ fontSize: 11, color: "#6b7280", letterSpacing: 1, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>{label}</p>
                    <p style={{ color: "#e8dcc8", fontSize: 15, marginTop: 4 }}>{value}</p>
                  </div>
                ) : null)}
              </div>

              {customInstructions.trim() && (
                <>
                  <hr style={{ border: "none", borderTop: "1px solid #1e2d3d", margin: "20px 0" }} />
                  <div>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                      <p style={{ fontSize: 11, color: "#c9913a", letterSpacing: 2, textTransform: "uppercase", fontFamily: "'Cinzel', serif" }}>
                        ✦ Your Custom Instructions
                      </p>
                      <button
                        onClick={() => setStep(2)}
                        style={{ background: "none", border: "1px solid #1e2d3d", borderRadius: 4, color: "#6b7280", padding: "3px 8px", fontSize: 11, cursor: "pointer", fontFamily: "'Cinzel', serif" }}
                      >
                        Edit
                      </button>
                    </div>
                    <p style={{ color: "#8aacbf", fontSize: 14, lineHeight: 1.7, fontStyle: "italic", whiteSpace: "pre-wrap" }}>
                      {customInstructions.trim()}
                    </p>
                  </div>
                </>
              )}
            </div>

            <div style={{ padding: "16px 20px", background: "#0a1a10", border: "1px solid #22c55e33", borderRadius: 8, marginBottom: 24 }}>
              <p style={{ fontSize: 14, color: "#22c55e", marginBottom: 6 }}>✦ Story Features Enabled</p>
              <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
                {["Character Memory", "Scene Images", subscription !== "free" ? "Voice Narration" : null, multiplayer ? "Co-Author Mode" : null, customInstructions.trim() ? "Custom Instructions" : null].filter(Boolean).map(f => (
                  <span key={f} className="tag" style={{ color: "#22c55e" }}>{f}</span>
                ))}
              </div>
            </div>

            <p style={{ color: "#6b7280", fontSize: 14, fontStyle: "italic", lineHeight: 1.6, marginBottom: 24 }}>
              Grok AI will begin with an opening scene based on your parameters. Characters you name and describe will be remembered throughout the entire story. Type your actions and choices to guide the narrative.
            </p>
          </div>
        )}
      </div>

      {/* Navigation */}
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 40 }}>
        <button className="btn-ghost" onClick={() => step > 1 ? setStep(s => s - 1) : onBack()} style={{ visibility: step === 1 ? "hidden" : "visible" }}>
          ← Previous
        </button>
        {step < 5 ? (
          <button className="btn-primary" onClick={() => canProceed() && setStep(s => s + 1)} style={{ opacity: canProceed() ? 1 : 0.4 }}>
            {step === 2 && !customInstructions.trim() ? "Skip →" : "Continue →"}
          </button>
        ) : (
          <button className="btn-primary" onClick={handleCreate} style={{ fontSize: 16, padding: "14px 40px" }}>
            ✦ Begin Story
          </button>
        )}
      </div>
    </div>
  );
}

// ============================================================
// STORY SCREEN (Main interactive story interface)
// ============================================================
function StoryScreen({ story, subscription, onBack, onUpdateStory, notify }) {
  const [messages, setMessages] = useState(story?.messages || []);
  const [characters, setCharacters] = useState(story?.characters || []);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [sceneImage, setSceneImage] = useState(null);
  const [imageLoading, setImageLoading] = useState(false);
  const [audioPlaying, setAudioPlaying] = useState(false);
  const [showChars, setShowChars] = useState(false);
  const [storyTitle, setStoryTitle] = useState(story?.title || "Untitled Story");
  const [started, setStarted] = useState(messages.length > 0);
  const [currentChoices, setCurrentChoices] = useState(null);
  const [showOtherInput, setShowOtherInput] = useState(false);
  const messagesEndRef = useRef(null);
  const tier = SUBSCRIPTION_TIERS[subscription];

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  // Build system prompt for this story
  const buildSystemPrompt = useCallback(() => {
    const genre = STORY_GENRES[story?.genre];
    const rating = CONTENT_RATINGS[story?.rating];
    const paramStr = Object.entries(story?.params || {}).filter(([, v]) => v).map(([k, v]) => `${k}: ${v}`).join(", ");
    const charStr = characters.length > 0
      ? `\n\nESTABLISHED CHARACTERS (always maintain consistency):\n${characters.map(c => `- ${c.name}: ${c.description}`).join("\n")}`
      : "";
    const customStr = story?.customInstructions?.trim()
      ? `\n\nUSER'S CUSTOM STORY INSTRUCTIONS (treat these as binding creative direction — honor them throughout the entire story):\n${story.customInstructions.trim()}`
      : "";

    return `${genre?.systemPrompt || "You are a master storyteller."}

CONTENT RATING: ${rating?.label} — ${rating?.description}. STRICTLY enforce this rating throughout.
STORY PARAMETERS: ${paramStr || "None specified — use your creative judgment."}
STORY TITLE: "${storyTitle}"
${charStr}${customStr}

CHARACTER MEMORY PROTOCOL: When new named characters appear, remember them exactly. When reintroducing characters, reference specific earlier events naturally. Consistency is paramount.

IMAGE DESCRIPTION PROTOCOL: After the narrative, add a JSON block on a new line: {"scene_prompt": "brief visual description for image generation, no text, cinematic"}

CHOICE PROTOCOL: After the scene_prompt block, add a second JSON block on a new line with exactly 3 choices for what the reader can do next. These must be meaningfully different — not variations of the same idea. One should be bold/risky, one measured/cautious, one unexpected/creative. Format: {"choices": ["Choice one text", "Choice two text", "Choice three text"]}

RESPONSE FORMAT: Narrative prose only. No meta-commentary. Address the reader as "you." Keep each response 150-300 words. Always end with both JSON blocks.`;
  }, [story, characters, storyTitle]);

  const extractCharacters = (text) => {
    const newChars = [];
    const namePattern = /\*([A-Z][a-z]+ [A-Z][a-z]+|[A-Z][a-z]+)\*/g;
    let match;
    while ((match = namePattern.exec(text)) !== null) {
      const name = match[1];
      if (!characters.find(c => c.name === name)) {
        newChars.push({ name, description: "Introduced in the story", firstSeen: messages.length });
      }
    }
    return newChars;
  };

  const extractScenePrompt = (text) => {
    try {
      const jsonMatch = text.match(/\{"scene_prompt":\s*"([^"]+)"\}/);
      return jsonMatch ? jsonMatch[1] : null;
    } catch { return null; }
  };

  const extractChoices = (text) => {
    try {
      const jsonMatch = text.match(/\{"choices":\s*(\[[^\]]+\])\}/);
      if (!jsonMatch) return null;
      const parsed = JSON.parse(jsonMatch[1].replace(/\\"/g, '"'));
      return Array.isArray(parsed) && parsed.length === 3 ? parsed : null;
    } catch { return null; }
  };

  const cleanText = (text) => text
    .replace(/\{"scene_prompt":[^}]+\}/g, "")
    .replace(/\{"choices":[^}]+\}\s*/g, "")
    .trim();

  const startStory = async () => {
    setLoading(true);
    setStarted(true);
    setCurrentChoices(null);
    setShowOtherInput(false);
    const starter = STORY_STARTERS[story?.genre] || "Your story begins...";
    try {
      const systemPrompt = buildSystemPrompt();
      const response = await callGrokAPI([
        { role: "user", content: `Begin the story. Opening scene. Use this as inspiration but make it fresh: "${starter}"` }
      ], systemPrompt);

      const scenePrompt = extractScenePrompt(response);
      const choices = extractChoices(response);
      const cleanResponse = cleanText(response);
      const newChars = extractCharacters(cleanResponse);

      const aiMsg = { role: "assistant", content: cleanResponse, id: Date.now(), scenePrompt };
      setMessages([aiMsg]);
      setCharacters(prev => [...prev, ...newChars]);
      setCurrentChoices(choices);
      if (scenePrompt) generateSceneImage(scenePrompt);

      onUpdateStory({ ...story, messages: [aiMsg], characters: [...characters, ...newChars] });
    } catch (e) {
      notify("Failed to start story. Check your API connection.", "error");
    }
    setLoading(false);
  };

  const sendMessage = async (overrideText) => {
    const text = overrideText ?? input.trim();
    if (!text || loading) return;
    setCurrentChoices(null);
    setShowOtherInput(false);
    const userMsg = { role: "user", content: text, id: Date.now() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);

    try {
      const systemPrompt = buildSystemPrompt();
      const apiMessages = newMessages.map(m => ({ role: m.role, content: m.content }));
      const response = await callGrokAPI(apiMessages, systemPrompt);

      const scenePrompt = extractScenePrompt(response);
      const choices = extractChoices(response);
      const cleanResponse = cleanText(response);
      const newChars = extractCharacters(cleanResponse);

      const aiMsg = { role: "assistant", content: cleanResponse, id: Date.now() + 1, scenePrompt };
      const updatedMessages = [...newMessages, aiMsg];
      setMessages(updatedMessages);
      const updatedChars = [...characters, ...newChars];
      setCharacters(updatedChars);
      setCurrentChoices(choices);

      if (scenePrompt) generateSceneImage(scenePrompt);
      onUpdateStory({ ...story, messages: updatedMessages, characters: updatedChars });
    } catch (e) {
      notify("Story interrupted. Try again.", "error");
      setMessages(newMessages.slice(0, -1));
    }
    setLoading(false);
  };

const generateSceneImage = async (prompt) => {
  if (!prompt) return;
  setImageLoading(true);
  setSceneImage(null);

  try {
    const imageUrl = await callGrokImageAPI(prompt);
    setSceneImage({ prompt, url: imageUrl });
  } catch (err) {
    console.error(err);
    // fallback to placeholder if you want
    setSceneImage({ prompt, url: null });
  } finally {
    setImageLoading(false);
  }
};

  const genre = STORY_GENRES[story?.genre];

  return (
    <div style={{ height: "100vh", display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ padding: "16px 24px", background: "#080c14", borderBottom: "1px solid #1e2d3d", display: "flex", justifyContent: "space-between", alignItems: "center", flexShrink: 0 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
          <button className="btn-ghost" onClick={onBack} style={{ padding: "6px 12px", fontSize: 12 }}>←</button>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <img src={SILVERFANG_LOGO} alt="logo" style={{ width: 28, height: 28, objectFit: "contain", filter: "drop-shadow(0 0 6px rgba(59,130,246,0.5))" }} />
              <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8f4ff", fontSize: 17, letterSpacing: 1 }}>{storyTitle}</h2>
            </div>
            <div style={{ display: "flex", gap: 8, marginTop: 4 }}>
              <span className="tag">{genre?.icon} {genre?.label?.replace(/^\S+ /, "")}</span>
              <span className="tag" style={{ color: CONTENT_RATINGS[story?.rating]?.color }}>{story?.rating}</span>
              {story?.multiplayer && <span className="tag" style={{ color: "#3b82f6" }}>👥</span>}
            </div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <button className="btn-ghost" onClick={() => setShowChars(!showChars)} style={{ fontSize: 12 }}>
            👤 {characters.length} Characters
          </button>
          {subscription !== "free" && (
            <button className="btn-ghost" onClick={() => setAudioPlaying(!audioPlaying)} style={{ fontSize: 12, color: audioPlaying ? "#22c55e" : "#c9913a" }}>
              {audioPlaying ? "🔊 Narrating" : "🔇 Narration"}
            </button>
          )}
        </div>
      </div>

      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        {/* Character Panel */}
        {showChars && (
          <div style={{ width: 220, background: "#060d18", borderRight: "1px solid #1e2d3d", padding: 16, overflowY: "auto", flexShrink: 0 }}>
            <h3 style={{ fontFamily: "'Cinzel', serif", fontSize: 12, color: "#c9913a", letterSpacing: 2, marginBottom: 16 }}>CHARACTERS</h3>
            {characters.length === 0 ? (
              <p style={{ color: "#3a4a5a", fontSize: 13, fontStyle: "italic" }}>Characters will appear here as they're introduced</p>
            ) : characters.map(c => (
              <div key={c.name} style={{ marginBottom: 16, padding: "12px", background: "#0a1120", borderRadius: 6, border: "1px solid #1e2d3d" }}>
                <p style={{ fontFamily: "'Cinzel', serif", color: "#c9bfa8", fontSize: 14, marginBottom: 4 }}>{c.name}</p>
                <p style={{ color: "#6b7280", fontSize: 12 }}>{c.description}</p>
              </div>
            ))}
          </div>
        )}

        {/* Main Content */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
          {/* Scene Image */}
          {(sceneImage || imageLoading) && (
            <div style={{ padding: "16px 24px", background: "#060d18", borderBottom: "1px solid #1e2d3d", flexShrink: 0 }}>
              <div style={{ height: 180, borderRadius: 8, overflow: "hidden", position: "relative", background: "#0a1120", border: "1px solid #1e2d3d" }}>
                {imageLoading ? (
                  <div className="shimmer" style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <p style={{ color: "#3a4a5a", fontFamily: "'Cinzel', serif", fontSize: 13, letterSpacing: 2 }}>RENDERING SCENE...</p>
                  </div>
                ) : sceneImage && (
                  <div style={{ width: "100%", height: "100%", background: "linear-gradient(135deg, #0a1827, #1a0a0a, #0a1a0a)", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 8 }}>
                    {/* Placeholder - replace with actual Grok image URL */}
                    <div style={{ fontSize: 32 }}>{genre?.icon}</div>
                    <p style={{ color: "#6b7280", fontSize: 12, fontStyle: "italic", textAlign: "center", maxWidth: 400, padding: "0 20px", lineHeight: 1.4 }}>
                      🖼️ Scene: {sceneImage.prompt?.slice(0, 100)}...
                    </p>
                    <p style={{ color: "#3a4a5a", fontSize: 11 }}>Grok image API renders here</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Messages */}
          <div style={{ flex: 1, overflowY: "auto", padding: "24px" }}>
            {!started ? (
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100%", gap: 24 }}>
                <div style={{ fontSize: 64 }}>{genre?.icon}</div>
                <div style={{ textAlign: "center", maxWidth: 480 }}>
                  <h3 style={{ fontFamily: "'Cinzel', serif", color: "#e8c060", fontSize: 22, letterSpacing: 2, marginBottom: 12 }}>{storyTitle}</h3>
                  <p style={{ color: "#8aacbf", fontSize: 16, lineHeight: 1.7, fontStyle: "italic", marginBottom: 28 }}>
                    {STORY_STARTERS[story?.genre]}
                  </p>
                  <button className="btn-primary" onClick={startStory} style={{ fontSize: 16, padding: "14px 40px" }}>
                    ✦ Begin This Story
                  </button>
                </div>
              </div>
            ) : (
              <div style={{ maxWidth: 720, margin: "0 auto" }}>
                {messages.map((msg, i) => (
                  <div key={msg.id || i} style={{ marginBottom: 28, animation: "fadeIn 0.5s ease" }}>
                    {msg.role === "assistant" ? (
                      <div>
                        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
                          <div style={{ width: 28, height: 28, borderRadius: "50%", background: "linear-gradient(135deg, #c9913a, #e8c060)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>✦</div>
                          <span style={{ fontFamily: "'Cinzel', serif", fontSize: 12, color: "#c9913a", letterSpacing: 2 }}>THE STORY</span>
                        </div>
                        <div style={{ background: "linear-gradient(135deg, #0d1827, #111520)", border: "1px solid #1e2d3d", borderRadius: "0 12px 12px 12px", padding: "20px 24px" }}>
                          <p style={{ fontSize: 17, lineHeight: 1.9, color: "#e0d4be", whiteSpace: "pre-wrap" }}>
                            {msg.content.split(/(\*\*[^*]+\*\*|\*[^*]+\*)/g).map((part, j) => {
                              if (part.startsWith("**") && part.endsWith("**")) return <strong key={j} style={{ color: "#e8c060" }}>{part.slice(2, -2)}</strong>;
                              if (part.startsWith("*") && part.endsWith("*")) return <em key={j} style={{ color: "#8aacbf" }}>{part.slice(1, -1)}</em>;
                              return part;
                            })}
                          </p>
                        </div>
                      </div>
                    ) : (
                      <div style={{ display: "flex", justifyContent: "flex-end", gap: 12 }}>
                        <div style={{ maxWidth: "75%" }}>
                          <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 8 }}>
                            <span style={{ fontFamily: "'Cinzel', serif", fontSize: 12, color: "#6b7280", letterSpacing: 1 }}>YOUR ACTION</span>
                          </div>
                          <div style={{ background: "#0a1a2a", border: "1px solid #1e3a5e", borderRadius: "12px 0 12px 12px", padding: "14px 20px" }}>
                            <p style={{ fontSize: 16, color: "#8aacbf", lineHeight: 1.7 }}>{msg.content}</p>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                ))}
                {loading && (
                  <div style={{ marginBottom: 28 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
                      <div style={{ width: 28, height: 28, borderRadius: "50%", background: "linear-gradient(135deg, #c9913a, #e8c060)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>✦</div>
                      <span style={{ fontFamily: "'Cinzel', serif", fontSize: 12, color: "#c9913a", letterSpacing: 2 }} className="pulse">WEAVING THE TALE...</span>
                    </div>
                    <div className="shimmer" style={{ height: 120, borderRadius: "0 12px 12px 12px", border: "1px solid #1e2d3d" }} />
                    <div className="shimmer" style={{ height: 20, borderRadius: 4, border: "1px solid #1e2d3d", marginTop: 8, width: "60%" }} />
                  </div>
                )}
                <div ref={messagesEndRef} />
              </div>
            )}
          </div>

          {/* Choice / Input Area */}
          {started && (
            <div style={{ padding: "20px 24px", background: "#060d18", borderTop: "1px solid #1e2d3d", flexShrink: 0 }}>
              <div style={{ maxWidth: 720, margin: "0 auto" }}>

                {/* AI-generated choices */}
                {!loading && currentChoices && !showOtherInput && (
                  <div style={{ animation: "fadeIn 0.4s ease" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
                      <div style={{ flex: 1, height: 1, background: "linear-gradient(90deg, transparent, #1e2d3d)" }} />
                      <span style={{ fontFamily: "'Cinzel', serif", fontSize: 11, color: "#6b7280", letterSpacing: 2, whiteSpace: "nowrap" }}>CHOOSE YOUR PATH</span>
                      <div style={{ flex: 1, height: 1, background: "linear-gradient(90deg, #1e2d3d, transparent)" }} />
                    </div>

                    <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 10 }}>
                      {currentChoices.map((choice, idx) => {
                        const icons = ["⚔️", "🛡️", "✨"];
                        const labels = ["Bold", "Measured", "Unexpected"];
                        const colors = ["#c9913a", "#3b82f6", "#8b5cf6"];
                        return (
                          <button
                            key={idx}
                            onClick={() => sendMessage(choice)}
                            style={{
                              background: "linear-gradient(135deg, #0d1827, #111520)",
                              border: `1px solid ${colors[idx]}33`,
                              borderRadius: 8,
                              padding: "14px 18px",
                              cursor: "pointer",
                              textAlign: "left",
                              transition: "all 0.2s",
                              display: "flex",
                              alignItems: "flex-start",
                              gap: 14,
                            }}
                            onMouseEnter={e => {
                              e.currentTarget.style.borderColor = `${colors[idx]}88`;
                              e.currentTarget.style.background = `linear-gradient(135deg, #0d1827, ${colors[idx]}11)`;
                              e.currentTarget.style.transform = "translateX(3px)";
                            }}
                            onMouseLeave={e => {
                              e.currentTarget.style.borderColor = `${colors[idx]}33`;
                              e.currentTarget.style.background = "linear-gradient(135deg, #0d1827, #111520)";
                              e.currentTarget.style.transform = "translateX(0)";
                            }}
                          >
                            <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4, flexShrink: 0, paddingTop: 2 }}>
                              <span style={{ fontSize: 18 }}>{icons[idx]}</span>
                              <span style={{ fontFamily: "'Cinzel', serif", fontSize: 9, color: colors[idx], letterSpacing: 1 }}>{labels[idx]}</span>
                            </div>
                            <div>
                              <span style={{ fontFamily: "'Cinzel', serif", fontSize: 11, color: colors[idx], letterSpacing: 1, display: "block", marginBottom: 4 }}>
                                OPTION {idx + 1}
                              </span>
                              <p style={{ color: "#c9bfa8", fontSize: 15, lineHeight: 1.55, fontFamily: "'Crimson Text', serif" }}>{choice}</p>
                            </div>
                          </button>
                        );
                      })}

                      {/* Option 4 — Other */}
                      <button
                        onClick={() => setShowOtherInput(true)}
                        style={{
                          background: "#0a0f1a",
                          border: "1px dashed #2a3d4f",
                          borderRadius: 8,
                          padding: "14px 18px",
                          cursor: "pointer",
                          textAlign: "left",
                          transition: "all 0.2s",
                          display: "flex",
                          alignItems: "center",
                          gap: 14,
                        }}
                        onMouseEnter={e => { e.currentTarget.style.borderColor = "#c9913a55"; e.currentTarget.style.background = "#0d1520"; }}
                        onMouseLeave={e => { e.currentTarget.style.borderColor = "#2a3d4f"; e.currentTarget.style.background = "#0a0f1a"; }}
                      >
                        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 4, flexShrink: 0, paddingTop: 2 }}>
                          <span style={{ fontSize: 18 }}>✍️</span>
                          <span style={{ fontFamily: "'Cinzel', serif", fontSize: 9, color: "#6b7280", letterSpacing: 1 }}>Custom</span>
                        </div>
                        <div>
                          <span style={{ fontFamily: "'Cinzel', serif", fontSize: 11, color: "#6b7280", letterSpacing: 1, display: "block", marginBottom: 4 }}>
                            OPTION 4 — WRITE YOUR OWN
                          </span>
                          <p style={{ color: "#6b7280", fontSize: 15, lineHeight: 1.55, fontFamily: "'Crimson Text', serif", fontStyle: "italic" }}>
                            Something else entirely... forge your own path
                          </p>
                        </div>
                      </button>
                    </div>
                  </div>
                )}

                {/* Free-text input — shown when "Other" is picked or no choices available */}
                {!loading && (showOtherInput || !currentChoices) && (
                  <div style={{ animation: "fadeIn 0.3s ease" }}>
                    {showOtherInput && (
                      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
                        <button
                          onClick={() => setShowOtherInput(false)}
                          style={{ background: "none", border: "1px solid #1e2d3d", borderRadius: 4, color: "#6b7280", padding: "4px 10px", fontSize: 12, cursor: "pointer", fontFamily: "'Cinzel', serif", letterSpacing: 1 }}
                        >
                          ← Back to Choices
                        </button>
                        <span style={{ fontFamily: "'Cinzel', serif", fontSize: 11, color: "#c9913a", letterSpacing: 2 }}>WRITE YOUR OWN PATH</span>
                      </div>
                    )}
                    <div style={{ display: "flex", gap: 12 }}>
                      <textarea
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
                        placeholder={showOtherInput ? "Describe exactly what you do — no limits..." : "What do you do? Describe your action, speak dialogue, or ask questions..."}
                        rows={3}
                        style={{ resize: "none", fontSize: 15, lineHeight: 1.6 }}
                        autoFocus={showOtherInput}
                      />
                      <button
                        onClick={() => sendMessage()}
                        disabled={!input.trim()}
                        style={{
                          width: 56,
                          background: !input.trim() ? "#1e2d3d" : "linear-gradient(135deg, #c9913a, #e8c060)",
                          border: "none", borderRadius: 6,
                          cursor: !input.trim() ? "not-allowed" : "pointer",
                          color: !input.trim() ? "#3a4a5a" : "#1a0f00",
                          fontSize: 20, flexShrink: 0, transition: "all 0.2s",
                        }}
                      >
                        ➤
                      </button>
                    </div>
                    <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 6 }}>
                      <span style={{ fontSize: 12, color: "#3a4a5a" }}>Shift+Enter for new line · Enter to send</span>
                    </div>
                  </div>
                )}

                {/* Loading state */}
                {loading && (
                  <div style={{ textAlign: "center", padding: "10px 0" }}>
                    <span style={{ fontFamily: "'Cinzel', serif", fontSize: 12, color: "#c9913a", letterSpacing: 3 }} className="pulse">
                      ✦ &nbsp; WEAVING THE TALE &nbsp; ✦
                    </span>
                  </div>
                )}

              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ============================================================
// COMMUNITY SCREEN
// ============================================================
function CommunityScreen({ subscription, onBack, notify }) {
  const [activeTab, setCommunityTab] = useState("trending");
  const [posts, setPosts] = useState(MOCK_COMMUNITY_POSTS);
  const [newPost, setNewPost] = useState("");
  const [postCategory, setPostCategory] = useState("discussion");
  const [chatMessages, setChatMessages] = useState([
    { user: "DragonScribe", avatar: "🐉", text: "Anyone else addicted to the murder mystery genre?", time: "2:14 PM" },
    { user: "NebulaNarrator", avatar: "🌌", text: "The character memory feature is incredible for long campaigns", time: "2:18 PM" },
    { user: "RomanceReader", avatar: "💕", text: "Just started my 8th story lol send help", time: "2:22 PM" },
  ]);
  const [chatInput, setChatInput] = useState("");

  const canPost = subscription !== "free";
  const tabs = [
    { id: "trending", label: "🔥 Trending" },
    { id: "tips", label: "💡 Tips & Tricks" },
    { id: "showcase", label: "✦ Showcase" },
    { id: "collab", label: "🤝 Collabs" },
    { id: "livechat", label: "💬 Live Chat" },
  ];

  const filteredPosts = activeTab === "trending" ? posts : posts.filter(p => p.category === activeTab);

  const handleLike = (id) => {
    setPosts(prev => prev.map(p => p.id === id ? { ...p, likes: p.likes + 1 } : p));
  };

  const handlePostSubmit = () => {
    if (!newPost.trim()) return;
    if (!canPost) { notify("Upgrade to post in the community", "error"); return; }
    const post = { id: Date.now(), user: "You", avatar: "📖", content: newPost, likes: 0, replies: 0, time: "Just now", category: postCategory };
    setPosts(prev => [post, ...prev]);
    setNewPost("");
    notify("Posted to community!");
  };

  const sendChat = () => {
    if (!chatInput.trim()) return;
    if (!canPost) { notify("Upgrade to participate in live chat", "error"); return; }
    setChatMessages(prev => [...prev, { user: "You", avatar: "📖", text: chatInput, time: new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) }]);
    setChatInput("");
  };

  return (
    <div style={{ minHeight: "100vh", padding: "24px 20px", maxWidth: 900, margin: "0 auto" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 32 }}>
        <button className="btn-ghost" onClick={onBack} style={{ padding: "8px 16px", fontSize: 12 }}>← Dashboard</button>
        <div>
          <h2 style={{ fontFamily: "'Cinzel', serif", color: "#e8f4ff", fontSize: 26, letterSpacing: 3 }}>THE FANG COMMUNITY</h2>
          <p style={{ color: "#6b7280", fontSize: 14, marginTop: 4 }}>Share ideas, tips, and stories with fellow storytellers</p>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", gap: 4, marginBottom: 28, overflowX: "auto" }}>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setCommunityTab(t.id)} style={{
            padding: "10px 18px", borderRadius: 6, border: `1px solid ${activeTab === t.id ? "#c9913a44" : "#1e2d3d"}`,
            background: activeTab === t.id ? "#1a2a1a" : "transparent",
            color: activeTab === t.id ? "#c9913a" : "#6b7280",
            fontFamily: "'Cinzel', serif", fontSize: 13, cursor: "pointer", whiteSpace: "nowrap",
            transition: "all 0.2s",
          }}>{t.label}</button>
        ))}
      </div>

      {activeTab === "livechat" ? (
        /* Live Chat */
        <div className="card" style={{ display: "flex", flexDirection: "column", height: 500 }}>
          <div style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", gap: 12, marginBottom: 16 }}>
            {chatMessages.map((m, i) => (
              <div key={i} style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                <div style={{ width: 36, height: 36, borderRadius: "50%", background: "#1e2d3d", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>{m.avatar}</div>
                <div>
                  <div style={{ display: "flex", gap: 8, alignItems: "baseline", marginBottom: 4 }}>
                    <span style={{ fontFamily: "'Cinzel', serif", fontSize: 13, color: "#c9bfa8" }}>{m.user}</span>
                    <span style={{ fontSize: 11, color: "#3a4a5a" }}>{m.time}</span>
                  </div>
                  <p style={{ fontSize: 15, color: "#8aacbf", lineHeight: 1.5 }}>{m.text}</p>
                </div>
              </div>
            ))}
          </div>
          <hr className="divider" />
          <div style={{ display: "flex", gap: 12 }}>
            <input value={chatInput} onChange={e => setChatInput(e.target.value)} onKeyDown={e => e.key === "Enter" && sendChat()} placeholder={canPost ? "Type a message..." : "Upgrade to chat..."} disabled={!canPost} />
            <button className="btn-primary" onClick={sendChat} disabled={!canPost} style={{ padding: "10px 20px", opacity: canPost ? 1 : 0.4 }}>Send</button>
          </div>
          {!canPost && <p style={{ fontSize: 12, color: "#ef4444", marginTop: 8 }}>Live chat requires a paid subscription</p>}
        </div>
      ) : (
        /* Posts Feed */
        <div>
          {/* New Post */}
          <div className="card" style={{ marginBottom: 24 }}>
            <div style={{ display: "flex", gap: 12, marginBottom: 12 }}>
              <select value={postCategory} onChange={e => setPostCategory(e.target.value)} style={{ flex: "0 0 auto", width: "auto" }}>
                <option value="discussion">💬 Discussion</option>
                <option value="tips">💡 Tips</option>
                <option value="showcase">✦ Showcase</option>
                <option value="collab">🤝 Collab</option>
              </select>
            </div>
            <textarea value={newPost} onChange={e => setNewPost(e.target.value)} placeholder={canPost ? "Share a story, tip, or find collaborators..." : "Upgrade to post in the community..."} rows={3} disabled={!canPost} style={{ marginBottom: 12 }} />
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ fontSize: 13, color: "#3a4a5a" }}>{canPost ? "Free members can read but not post" : "Upgrade to participate"}</span>
              <button className="btn-primary" onClick={handlePostSubmit} disabled={!canPost} style={{ padding: "10px 24px", opacity: canPost ? 1 : 0.4 }}>Post</button>
            </div>
          </div>

          {/* Posts */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {filteredPosts.map(post => (
              <div key={post.id} className="card card-hover" style={{ animation: "fadeIn 0.4s ease" }}>
                <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                  <div style={{ width: 44, height: 44, borderRadius: "50%", background: "#1e2d3d", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>{post.avatar}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap", marginBottom: 8 }}>
                      <span style={{ fontFamily: "'Cinzel', serif", color: "#c9bfa8", fontSize: 14 }}>{post.user}</span>
                      <span className="tag">{post.category}</span>
                      <span style={{ color: "#3a4a5a", fontSize: 13 }}>{post.time}</span>
                    </div>
                    <p style={{ color: "#c9bfa8", fontSize: 15, lineHeight: 1.7 }}>{post.content}</p>
                    <div style={{ display: "flex", gap: 20, marginTop: 14 }}>
                      <button onClick={() => handleLike(post.id)} style={{ background: "none", border: "none", color: "#6b7280", cursor: "pointer", fontSize: 14, display: "flex", alignItems: "center", gap: 4 }}>
                        ♥ {post.likes}
                      </button>
                      <button style={{ background: "none", border: "none", color: "#6b7280", cursor: "pointer", fontSize: 14 }}>
                        💬 {post.replies} replies
                      </button>
                      <button style={{ background: "none", border: "none", color: "#6b7280", cursor: "pointer", fontSize: 14 }}>
                        ↗ Share
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
